#!/usr/bin/env node
import { existsSync, mkdirSync, rmSync, writeFileSync, cpSync } from 'node:fs';
import { dirname, resolve } from 'node:path';
import { spawnSync } from 'node:child_process';

const root = process.cwd();
const releaseDir = resolve(root, 'release', 'api-architex-co-za');
const bundlePath = resolve(root, 'release', 'api-architex-co-za-node.tgz');

const requiredPaths = [
  'api',
  'src/lib',
  'src/services',
  'src/types.ts',
  'api-server.ts',
  'server.ts',
  'package.json',
  'package-lock.json',
  'firebase-applet-config.json',
  '.env.production.example',
  'docs/deployment/api-architex-co-za-cpanel.md',
  'scripts/cpanel-api-smoke.mjs',
];

function fail(message) {
  console.error(`API bundle failed: ${message}`);
  process.exit(1);
}

for (const path of requiredPaths) {
  if (!existsSync(resolve(root, path))) fail(`missing ${path}`);
}

rmSync(releaseDir, { recursive: true, force: true });
mkdirSync(releaseDir, { recursive: true });

for (const path of requiredPaths) {
  const source = resolve(root, path);
  const target = resolve(releaseDir, path);
  mkdirSync(dirname(target), { recursive: true });
  if (source.endsWith('/')) continue;
  if (existsSync(source)) {
    cpSync(source, target, { recursive: true, force: true });
  }
}

writeFileSync(resolve(releaseDir, '.cpanel.yml'), `---\ndeployment:\n  tasks:\n    - /bin/echo \"Architex API bundle unpacked. Configure cPanel Node.js App manually, then run npm ci --include=dev.\"\n`, 'utf8');

writeFileSync(resolve(releaseDir, '.htaccess'), `<IfModule mod_rewrite.c>\n  RewriteEngine On\n  RewriteRule ^api/health/?$ health.php [L]\n  RewriteRule ^api/auth/check-admin/?$ auth-check-admin.php [L]\n</IfModule>\n\n<IfModule mod_headers.c>\n  Header always set X-Content-Type-Options \"nosniff\"\n  Header always set Referrer-Policy \"strict-origin-when-cross-origin\"\n</IfModule>\n`, 'utf8');

const phpCorsPrelude = `<?php\n$allowed = [\n  'https://test.architex.co.za',\n  'https://architex.co.za',\n  'https://www.architex.co.za',\n];\n$origin = $_SERVER['HTTP_ORIGIN'] ?? '';\nif (in_array($origin, $allowed, true)) {\n  header('Access-Control-Allow-Origin: ' . $origin);\n  header('Vary: Origin');\n  header('Access-Control-Allow-Credentials: true');\n}\n`;

writeFileSync(resolve(releaseDir, 'health.php'), `${phpCorsPrelude}header('Access-Control-Allow-Methods: GET, OPTIONS');\nheader('Access-Control-Allow-Headers: Authorization, Content-Type');\nheader('Content-Type: application/json');\nheader('Cache-Control: no-cache, no-store, must-revalidate');\nif ($_SERVER['REQUEST_METHOD'] === 'OPTIONS') {\n  http_response_code(204);\n  exit;\n}\necho json_encode([\n  'status' => 'ok',\n  'service' => 'architex-api',\n  'mode' => 'cpanel-php-health-check',\n  'timestamp' => gmdate('c'),\n]);\n`, 'utf8');

writeFileSync(resolve(releaseDir, 'auth-check-admin.php'), `${phpCorsPrelude}header('Access-Control-Allow-Methods: POST, OPTIONS');\nheader('Access-Control-Allow-Headers: Authorization, Content-Type');\nheader('Content-Type: application/json');\nheader('Cache-Control: no-cache, no-store, must-revalidate');\nif ($_SERVER['REQUEST_METHOD'] === 'OPTIONS') {\n  http_response_code(204);\n  exit;\n}\nhttp_response_code(401);\necho json_encode([\n  'error' => 'Unauthorized',\n  'message' => 'Node API is not active on cPanel yet; unauthenticated admin check fallback returns JSON for smoke safety.',\n  'service' => 'architex-api',\n  'mode' => 'cpanel-php-auth-fallback',\n  'timestamp' => gmdate('c'),\n]);\n`, 'utf8');

writeFileSync(resolve(releaseDir, 'README-api-architex-co-za.md'), `# api.architex.co.za Node API bundle\n\nGenerated by \`npm run deploy:api:bundle\`.\n\nUpload this directory or \`../api-architex-co-za-node.tgz\` to the cPanel account for \`api.architex.co.za\`.\n\nThe bundle includes small PHP fallbacks for \`/api/health\` and unauthenticated \`/api/auth/check-admin\` so remote smoke checks return JSON instead of LiteSpeed HTML while the cPanel Node.js app is being activated. Full API functionality still requires the Node app.\n\nDo not add secrets to this bundle. Configure environment variables in cPanel Node.js App.\n\nStart command: \`npm run start:api:host\`\nHealth check: \`node scripts/cpanel-api-smoke.mjs https://api.architex.co.za\`\n`, 'utf8');

const tar = spawnSync('tar', ['-czf', bundlePath, '-C', resolve(root, 'release'), 'api-architex-co-za'], { stdio: 'inherit' });
if (tar.status !== 0) fail('tar command failed');

console.log(`Created ${bundlePath}`);
